const HTMLParser = require("../parse-html");

function getExample(exampleHTML) {
  const config = {
    phrase: ".example-box",
    meaning: ".translation-example-box",
  };

  const parser = new HTMLParser();
  const $ = parser.parseHTML(exampleHTML);
  const data = parser.extractData($, config);
  return data;
}

function getMeaning(meaningHTML) {
  const config = {
    num: "h2 .translation-index",
    word: "h2 strong",
    info: "h2 small",
    examples: {
      selector: "ul li",
      multiple: true,
      extractHTML: true,
      transform: (examples) => examples.map(getExample),
    },
  };

  const parser = new HTMLParser();
  const $ = parser.parseHTML(meaningHTML);
  const data = parser.extractData($, config);
  return data;
}

async function saveToGitHub(data, filename) {
  const owner = 'YOUR_GITHUB_USERNAME';
  const repo = 'YOUR_REPO_NAME';
  const path = `data/${filename}`;
  const content = Buffer.from(JSON.stringify(data, null, 2)).toString('base64');

  const response = await fetch(`https://api.github.com/repos/${owner}/${repo}/contents/${path}`, {
    method: 'PUT',
    headers: {
      'Authorization': `token ${process.env.GITHUB_TOKEN}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      message: `Add parsed data: ${filename}`,
      content: content,
    }),
  });

  if (!response.ok) {
    throw new Error(`GitHub API error: ${response.statusText}`);
  }

  return response.json();
}

export default async function handler(req, res) {
  const { url, save } = req.query;

  if (!url) {
    return res.status(400).json({ error: 'URL parameter is required' });
  }

  const parser = new HTMLParser();
  const config = {
    word: ".word-box > h1",
    type: ".word-box > .part-of-speech",
    attrs: {
      selector: ".word-box .badge-pill",
      multiple: true,
    },
    helper: ".word-box > .text-muted.small.rtl",
    meanings: {
      selector: ".word-row:has(.translation-index)",
      multiple: true,
      extractHTML: true,
      transform: (meanings) => meanings.map(getMeaning),
    },
  };

  try {
    const result = await parser.parseURL(url, config);

    // If save parameter is provided, save to GitHub
    if (save) {
      const filename = `${save}.json`;
      await saveToGitHub(result.data, filename);
      res.json({ 
        data: result.data, 
        saved: true, 
        filename: filename,
        message: `Data saved to GitHub: data/${filename}`
      });
    } else {
      res.json(result.data);
    }
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
}
